def compute_scores_for_candidates(cands, target_norm):
    out = []
    for s_id, a_id, text, norm in cands:
        out.append({
            "surah_id": s_id,
            "ayah_id": a_id,
            "text": text,
            "norm": norm,
            "lcs": lcs_ratio(norm, target_norm),
            "f1": token_f1(norm, target_norm),
            "len": len(norm)
        })
